def _arc_cap(model, m, n, sa):
    return model.x[m, n, sa] <= 3
model.uniform_cap = Constraint(model.arc, rule=_arc_cap)

def _lane_cap(model, j):
    return model.x['n1', j, 'a1'] <= 5 if ('n1', j, 'a1') in model.arc else Constraint.Skip
model.depot_lane_cap = Constraint(model.n, rule=_lane_cap)

def _direct_service(model, j):
    return model.x['n1', j, 'a1'] >= 1 if (value(model.demand[j]) > 0 and ('n1', j, 'a1') in model.arc) else Constraint.Skip
model.direct_service = Constraint(model.n, rule=_direct_service)
